const body = $input.item.json.body || $input.item.json;
const headers = $input.item.json.headers || {};

// Detect platform from webhook path or payload structure
let platform = 'unknown';
let audioUrl = null;
let senderId = null;
let messageId = null;
let audioMetadata = {};

if (body.platform === 'whatsapp' || body.object === 'whatsapp_business_account') {
  platform = 'whatsapp';
  const message = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0] || body;
  senderId = message.from || body.from;
  messageId = message.id || body.messageId;

  if (message.type === 'audio' || message.audio) {
    const audio = message.audio || {};
    audioUrl = audio.url || body.audio?.url;
    audioMetadata = {
      mimeType: audio.mime_type || audio.mimeType || 'audio/ogg',
      duration: audio.duration || 0,
      sha256: audio.sha256 || null
    };
  } else if (message.type === 'voice' || message.voice) {
    const voice = message.voice || {};
    audioUrl = voice.url || body.audio?.url;
    audioMetadata = {
      mimeType: 'audio/ogg',
      duration: voice.duration || 0,
      sha256: voice.sha256 || null
    };
  }
} else if (body.update_id || body.message?.voice || body.platform === 'telegram') {
  platform = 'telegram';
  const message = body.message || body;
  senderId = message.from?.id?.toString() || message.chat?.id?.toString() || body.from;
  messageId = message.message_id?.toString() || body.messageId;

  if (message.voice) {
    audioUrl = `https://api.telegram.org/file/bot${process.env.TELEGRAM_BOT_TOKEN}/${message.voice.file_path}`;
    audioMetadata = {
      mimeType: message.voice.mime_type || 'audio/ogg',
      duration: message.voice.duration || 0,
      fileId: message.voice.file_id
    };
  } else if (message.audio) {
    audioUrl = `https://api.telegram.org/file/bot${process.env.TELEGRAM_BOT_TOKEN}/${message.audio.file_path}`;
    audioMetadata = {
      mimeType: message.audio.mime_type || 'audio/mpeg',
      duration: message.audio.duration || 0,
      fileId: message.audio.file_id
    };
  }
}

if (!audioUrl) {
  throw new Error(`No audio/voice message found in ${platform} webhook payload`);
}

if (!senderId) {
  throw new Error('Unable to identify sender from webhook payload');
}

// Normalize sender ID to E.164 format if possible
let normalizedSenderId = senderId;
if (platform === 'whatsapp' && !senderId.startsWith('+')) {
  normalizedSenderId = '+' + senderId;
}

const normalizedMessage = {
  messageId: `${platform}-${messageId || Date.now()}`,
  platform,
  senderId: normalizedSenderId,
  audioUrl,
  audioMetadata,
  receivedAt: new Date().toISOString(),
  conversationId: body.context?.conversationId || `conv-${normalizedSenderId}`,
  isFollowUp: !!body.context?.previousMessageId,
  previousMessageId: body.context?.previousMessageId || null,
  webhookSource: $node.name,
  rawPayload: body
};

return { json: { normalizedMessage } };

const transcriptionResponse = $input.item.json;
const normalizedMessage = $('Normalize Message Input').item.json.normalizedMessage;

// Extract transcription text
const transcribedText = transcriptionResponse.text || '';
const language = transcriptionResponse.language || 'en';
const duration = transcriptionResponse.duration || normalizedMessage.audioMetadata.duration || 0;

if (!transcribedText || transcribedText.trim().length < 3) {
  throw new Error('Transcription failed or audio was too short/unclear');
}

// Calculate confidence proxy from metadata
const segments = transcriptionResponse.segments || [];
const avgConfidence = segments.length > 0 
  ? segments.reduce((sum, seg) => sum + (seg.no_speech_prob || 0), 0) / segments.length
  : 0;

const transcriptionData = {
  normalizedMessage,
  transcription: {
    text: transcribedText.trim(),
    language,
    duration,
    wordCount: transcribedText.split(/\s+/).length,
    detectedLanguage: language,
    confidenceScore: Math.round((1 - avgConfidence) * 100),
    segments: segments.map(s => ({
      text: s.text,
      start: s.start,
      end: s.end,
      confidence: 1 - (s.no_speech_prob || 0)
    }))
  },
  transcribedAt: new Date().toISOString()
};

return { json: transcriptionData };

// Get intent classification
const intentRaw = $('Claude AI Intent Classification & Entity Extraction').item.json;
let intentText = intentRaw.response || intentRaw.output || intentRaw.text || '';
if (intentRaw.content && Array.isArray(intentRaw.content)) {
  intentText = intentRaw.content[0]?.text || '';
}
const cleanIntent = intentText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
const travelIntent = JSON.parse(cleanIntent);

// Get transcription data
const transcriptionData = $('Extract and Validate Transcription').item.json;

// Get user profile
const userProfiles = $('Fetch User Profile & Preferences').all().map(i => i.json);
const senderId = transcriptionData.normalizedMessage.senderId;
const userProfile = userProfiles.find(p => p.phoneNumber === senderId || p.telegramId === senderId) || {
  phoneNumber: senderId,
  name: 'Unknown User',
  defaultDepartureCity: 'Not Set',
  preferredCurrency: 'USD',
  loyaltyPrograms: [],
  dietaryRestrictions: [],
  travelClass: 'economy',
  budgetLevel: 'moderate'
};

// Get conversation history
const conversationHistory = $('Fetch Recent Conversation Context').all().map(i => i.json)
  .filter(c => c.userId === senderId)
  .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp))
  .slice(0, 5);

// Fill missing information from user profile
if (!travelIntent.destinations.from?.city && userProfile.defaultDepartureCity !== 'Not Set') {
  travelIntent.destinations.from = {
    city: userProfile.defaultDepartureCity,
    country: userProfile.defaultDepartureCountry || 'USA',
    iataCode: userProfile.defaultDepartureIATA || 'NYC',
    confidence: 80,
    source: 'user_profile_default'
  };
  travelIntent.missingInformation = travelIntent.missingInformation.filter(
    m => !m.includes('departure city')
  );
}

// Apply budget preferences if not specified
if (!travelIntent.budget?.amount) {
  const budgetDefaults = {
    'budget': 1000,
    'economy': 2000,
    'moderate': 4000,
    'premium': 8000,
    'luxury': 15000
  };
  travelIntent.budget = {
    amount: budgetDefaults[userProfile.budgetLevel] || 3000,
    currency: userProfile.preferredCurrency || 'USD',
    perPerson: true,
    category: userProfile.budgetLevel,
    source: 'user_profile_default'
  };
}

// Apply travel class preference if not specified
if (!travelIntent.preferences?.flightClass) {
  travelIntent.preferences = travelIntent.preferences || {};
  travelIntent.preferences.flightClass = userProfile.travelClass || 'economy';
}

// Merge dietary and accessibility requirements
if (userProfile.dietaryRestrictions?.length > 0) {
  travelIntent.specialRequirements = [
    ...travelIntent.specialRequirements,
    ...userProfile.dietaryRestrictions.map(d => `dietary: ${d}`)
  ];
}

if (userProfile.loyaltyPrograms?.length > 0) {
  travelIntent.preferences.loyaltyPrograms = userProfile.loyaltyPrograms;
}

const enrichedRequest = {
  transcriptionData,
  travelIntent,
  userProfile: {
    id: senderId,
    name: userProfile.name,
    defaultDepartureCity: userProfile.defaultDepartureCity,
    preferredCurrency: userProfile.preferredCurrency,
    budgetLevel: userProfile.budgetLevel,
    travelClass: userProfile.travelClass,
    loyaltyPrograms: userProfile.loyaltyPrograms || [],
    pastTripCount: userProfile.pastTripCount || 0
  },
  conversationContext: {
    recentMessages: conversationHistory.length,
    lastInteraction: conversationHistory[0]?.timestamp || null,
    priorSearches: conversationHistory.map(c => c.searchSummary).filter(Boolean)
  },
  enrichedAt: new Date().toISOString(),
  readyForSearch: !travelIntent.needsClarification
};

return [{ json: enrichedRequest }];

const enrichedRequest = $('Merge Intent, Profile & Context').item.json;
const flightResults = $('Search Flights (Skyscanner/Kiwi.com)').item.json;
const hotelResults = $('Search Hotels (Booking.com API)').item.json;
const activityResults = $('Search Activities & Tours').item.json;

// Extract and normalize flight options
const flights = (flightResults.itineraries || flightResults.data?.itineraries || []).map(flight => ({
  type: 'flight',
  airline: flight.legs?.[0]?.carriers?.marketing?.[0]?.name || 'Unknown',
  flightNumber: flight.legs?.[0]?.segments?.[0]?.flightNumber || 'N/A',
  departure: {
    time: flight.legs?.[0]?.departure,
    airport: flight.legs?.[0]?.origin?.displayCode
  },
  arrival: {
    time: flight.legs?.[0]?.arrival,
    airport: flight.legs?.[0]?.destination?.displayCode
  },
  duration: flight.legs?.[0]?.durationInMinutes || 0,
  stops: flight.legs?.[0]?.stopCount || 0,
  price: {
    amount: flight.pricingOptions?.[0]?.price?.amount || 9999,
    currency: flight.pricingOptions?.[0]?.price?.unit || 'USD'
  },
  bookingLink: flight.pricingOptions?.[0]?.items?.[0]?.deepLink || '#',
  score: 0
})).slice(0, 5);

// Extract and normalize hotel options
const hotels = (hotelResults.results || hotelResults.data?.hotels || []).map(hotel => ({
  type: 'hotel',
  name: hotel.name || 'Unknown Hotel',
  stars: hotel.stars || hotel.class || 3,
  rating: hotel.reviewScore || hotel.rating || 0,
  reviewCount: hotel.reviewCount || 0,
  price: {
    amount: hotel.minTotalPrice || hotel.price?.total || 999,
    currency: hotel.currencyCode || 'USD',
    perNight: true
  },
  location: hotel.address || hotel.location?.address || 'Unknown',
  amenities: hotel.facilities || [],
  images: hotel.photos?.slice(0, 3) || [],
  bookingLink: hotel.url || '#',
  score: 0
})).slice(0, 5);

// Extract and normalize activity options
const activities = (activityResults.products || activityResults.data?.activities || []).map(activity => ({
  type: 'activity',
  title: activity.title || activity.name || 'Unknown Activity',
  rating: activity.rating || 0,
  reviewCount: activity.reviewCount || 0,
  duration: activity.duration || 'Variable',
  category: activity.category || 'General',
  price: {
    amount: activity.price?.amount || activity.fromPrice || 50,
    currency: activity.price?.currency || 'USD'
  },
  description: activity.description?.substring(0, 150) || '',
  bookingLink: activity.productUrl || '#',
  score: 0
})).slice(0, 5);

// Smart ranking algorithm
function calculateScore(item, budget, preferences) {
  let score = 0;

  if (item.type === 'flight') {
    // Price factor (40%)
    const priceFactor = 1 - (item.price.amount / budget.amount);
    score += priceFactor * 40;

    // Duration factor (30%) - shorter is better
    const durationFactor = item.duration > 0 ? Math.max(0, 1 - (item.duration / 1000)) : 0.5;
    score += durationFactor * 30;

    // Stops penalty (30%)
    score += (item.stops === 0 ? 30 : item.stops === 1 ? 15 : 5);
  }

  if (item.type === 'hotel') {
    // Price factor (30%)
    const nightlyBudget = budget.amount / 7; // Assume week trip
    const priceFactor = 1 - Math.min(1, item.price.amount / nightlyBudget);
    score += priceFactor * 30;

    // Rating factor (40%)
    score += (item.rating / 10) * 40;

    // Stars match (30%)
    const starMatch = Math.abs(item.stars - (preferences.hotelStars || 3)) === 0 ? 30 : 15;
    score += starMatch;
  }

  if (item.type === 'activity') {
    // Rating factor (50%)
    score += (item.rating / 5) * 50;

    // Review count factor (20%)
    const reviewFactor = Math.min(1, item.reviewCount / 100);
    score += reviewFactor * 20;

    // Price factor (30%)
    const activityBudget = budget.amount * 0.2; // 20% of budget for activities
    const priceFactor = 1 - Math.min(1, item.price.amount / activityBudget);
    score += priceFactor * 30;
  }

  return Math.round(score);
}

// Calculate scores
flights.forEach(f => f.score = calculateScore(f, enrichedRequest.travelIntent.budget, enrichedRequest.travelIntent.preferences));
hotels.forEach(h => h.score = calculateScore(h, enrichedRequest.travelIntent.budget, enrichedRequest.travelIntent.preferences));
activities.forEach(a => a.score = calculateScore(a, enrichedRequest.travelIntent.budget, enrichedRequest.travelIntent.preferences));

// Sort by score
flights.sort((a, b) => b.score - a.score);
hotels.sort((a, b) => b.score - a.score);
activities.sort((a, b) => b.score - a.score);

// Calculate total package estimate
const topFlight = flights[0];
const topHotel = hotels[0];
const estimatedTotal = (topFlight?.price.amount || 0) + (topHotel?.price.amount || 0) * 7;
const withinBudget = estimatedTotal <= enrichedRequest.travelIntent.budget.amount;

return [{
  json: {
    enrichedRequest,
    searchResults: {
      flights,
      hotels,
      activities,
      totalResults: flights.length + hotels.length + activities.length
    },
    topRecommendations: {
      flight: flights[0] || null,
      hotel: hotels[0] || null,
      activity: activities[0] || null,
      estimatedTotal,
      withinBudget,
      budgetRemaining: enrichedRequest.travelIntent.budget.amount - estimatedTotal
    },
    searchedAt: new Date().toISOString()
  }
}];

