const responseRaw = $input.item.json;
let responseText = responseRaw.response || responseRaw.output || responseRaw.text || '';
if (responseRaw.content && Array.isArray(responseRaw.content)) {
  responseText = responseRaw.content[0]?.text || '';
}

const cleanResponse = responseText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
const aiResponse = JSON.parse(cleanResponse);

const aggregateData = $('Aggregate and Rank Results').item.json;

// Build calendar event object for Google Calendar API
const calendarEvent = {
  summary: aiResponse.calendarEvent?.title || `Trip to ${aggregateData.enrichedRequest.travelIntent.destinations.to[0].city}`,
  description: aiResponse.calendarEvent?.description || aiResponse.shortSummary,
  location: aiResponse.calendarEvent?.location || aggregateData.enrichedRequest.travelIntent.destinations.to[0].city,
  start: {
    date: aggregateData.enrichedRequest.travelIntent.dates.departure.exact,
    timeZone: 'America/New_York'
  },
  end: {
    date: aggregateData.enrichedRequest.travelIntent.dates.return.exact,
    timeZone: 'America/New_York'
  },
  reminders: {
    useDefault: false,
    overrides: [
      { method: 'popup', minutes: 2880 }, // 2 days before
      { method: 'email', minutes: 10080 } // 1 week before
    ]
  },
  colorId: '9', // Blue color for travel events
  extendedProperties: {
    private: {
      tripType: aggregateData.enrichedRequest.travelIntent.primaryIntent,
      budget: aggregateData.enrichedRequest.travelIntent.budget.amount.toString(),
      flightPrice: aggregateData.topRecommendations.flight?.price.amount.toString() || '0',
      hotelPrice: aggregateData.topRecommendations.hotel?.price.amount.toString() || '0'
    }
  }
};

return {
  json: {
    aggregateData,
    aiResponse,
    calendarEvent,
    delivery: {
      platform: aggregateData.enrichedRequest.transcriptionData.normalizedMessage.platform,
      recipientId: aggregateData.enrichedRequest.transcriptionData.normalizedMessage.senderId,
      messageId: aggregateData.enrichedRequest.transcriptionData.normalizedMessage.messageId
    },
    generatedAt: new Date().toISOString()
  }
};
